import 'prosekit/basic/style.css'
import 'prosekit/basic/typography.css'

import { createEditor } from 'prosekit/core'
import { ProseKit } from 'prosekit/react'
import { useMemo } from 'react'

import { defineExtension } from './extension'
import UserMenuDynamic from './user-menu-dynamic'

export default function Editor() {
  const editor = useMemo(() => {
    const extension = defineExtension()
    return createEditor({ extension })
  }, [])

  return (
    <ProseKit editor={editor}>
      <div className="box-border h-full w-full min-h-36 overflow-y-hidden overflow-x-hidden rounded-md border border-solid border-gray-200 dark:border-gray-700 shadow-sm flex flex-col bg-white dark:bg-gray-950 text-black dark:text-white">
        <div className="relative w-full flex-1 box-border overflow-y-auto">
          <div ref={editor.mount} className="ProseMirror box-border min-h-full px-[max(4rem,calc(50%-20rem))] py-8 outline-hidden outline-0 [&_span[data-mention=user]]:text-blue-500 [&_span[data-mention=tag]]:text-violet-500"></div>
          <UserMenuDynamic />
        </div>
      </div>
    </ProseKit>
  )
}

import { defineBasicExtension } from 'prosekit/basic'
import { union } from 'prosekit/core'
import { defineMention } from 'prosekit/extensions/mention'
import { definePlaceholder } from 'prosekit/extensions/placeholder'

export function defineExtension() {
  return union(
    defineBasicExtension(),
    definePlaceholder({
      placeholder: 'Type @ to mention someone...',
    }),
    defineMention(),
  )
}

export type EditorExtension = ReturnType<typeof defineExtension>

import { useEffect, useState } from 'react'

import type { User } from '../../sample/sample-query-users'
import { queryUsers } from '../../sample/sample-query-users'

/**
 * Simulate a user searching with some delay.
 */
export function useUserQuery(query: string, enabled: boolean) {
  const [users, setUsers] = useState<User[]>([])
  const [loading, setLoading] = useState(true)

  if (!enabled && users.length > 0) {
    setUsers([])
  }

  useEffect(() => {
    if (!enabled) {
      return
    }

    let cancelled = false

    void (async () => {
      setLoading(true)
      const filteredUsers = await queryUsers(query)
      if (cancelled) {
        return
      }
      setUsers(filteredUsers)
      setLoading(false)
    })()

    return () => {
      cancelled = true
    }
  }, [enabled, query])

  return { loading, users }
}

import { useState } from 'react'

import { UserMenu } from '../../ui/user-menu'

import { useUserQuery } from './use-user-query'

export default function UserMenuDynamic() {
  const [query, setQuery] = useState('')
  const [open, setOpen] = useState(false)

  const { loading, users } = useUserQuery(query, open)

  return (
    <UserMenu
      users={users}
      loading={loading}
      onQueryChange={setQuery}
      onOpenChange={setOpen}
    />
  )
}
